import type {
  StockVerdictV2,
  PillarVerdict,
  SegmentVerdictV2,
  QualSignal,
  NewsEvent,
  ConfidenceIndicator,
} from '@/types'
import { getScoreBandEnum } from '@/lib/scoring'
import { getOverallVerdict } from '@/lib/scoring'

// ============================================================
// HELPER: Build signal groups from scored signals
// ============================================================

function buildSignal(
  id: string, name: string, group: string,
  escalationTier: 'hard' | 'soft' | 'score_only',
  score: number,
  state: QualSignal['state'],
  userText: string,
  isTriggered = false,
): QualSignal {
  return { id, name, group, escalationTier, score, state, userText, isTriggered, version: 'v1' }
}

function buildConfidence(computed: number, total: number): ConfidenceIndicator {
  return {
    signalsComputed: computed,
    signalsTotal: total,
    state: computed === total ? 'full' : computed >= total * 0.7 ? 'partial' : 'limited_history',
    tooltip: `Based on ${computed} of ${total} signals`,
    dataRange: 'FY20–FY24',
  }
}

