// ============================================================
// BUILD STOCK VERDICT V2
// ============================================================

function buildPillarVerdict(
  pillar: 'quant' | 'qual' | 'risk',
  name: string,
  segments: SegmentVerdictV2[]
): PillarVerdict {
  // Compute weighted score from scored segments
  const scoredSegments = segments.filter(s => s.scoringType === 'scored' && s.score !== undefined)
  const totalWeight = scoredSegments.reduce((sum, s) => sum + (s.weight || 0), 0)
  const weightedScore = totalWeight > 0
    ? Math.round(scoredSegments.reduce((sum, s) => sum + (s.score! * (s.weight || 0)), 0) / totalWeight)
    : 0

  const scoreBand = getScoreBandEnum(weightedScore)

  const labels: Record<string, string> = {
    strong: 'STRONG', good: 'GOOD', mixed: 'MIXED', weak: 'WEAK', suppressed: 'SUPPRESSED',
  }

  return {
    pillar,
    name,
    score: weightedScore,
    scoreBand,
    label: labels[scoreBand],
    summary: `${name} analysis based on ${segments.length} segments`,
    segments,
  }
}

function buildStockVerdictV2(
  stockId: string,
  stockName: string,
  ticker: string,
  sector: string,
  quantSegments: SegmentVerdictV2[],
  qualFactors: SegmentVerdictV2[],
  newsEvents: NewsEvent[],
  profileId: string,
): StockVerdictV2 {
  const quantPillar = buildPillarVerdict('quant', 'Quantitative Analysis', quantSegments)
  const qualPillar = buildPillarVerdict('qual', 'Qualitative Analysis', qualFactors)

  // Risk pillar (aggregated from red flags across both pillars)
  const allRedFlags = [...quantSegments, ...qualFactors]
    .flatMap(s => s.redFlags || [])
  const riskScore = allRedFlags.length === 0 ? 80 : Math.max(20, 80 - allRedFlags.length * 15)
  const riskPillar: PillarVerdict = {
    pillar: 'risk',
    name: 'Risk Assessment',
    score: riskScore,
    scoreBand: getScoreBandEnum(riskScore),
    label: riskScore >= 80 ? 'LOW RISK' : riskScore >= 60 ? 'MODERATE' : 'ELEVATED',
    summary: allRedFlags.length === 0
      ? 'No red flags detected across analysis'
      : `${allRedFlags.length} risk factor(s) identified`,
    segments: [],
  }

  // Overall score — independent weighted computation
  // Simple weighted average for mock: Quant 50% + Qual 30% + Risk 20%
  const overallScore = Math.round(
    quantPillar.score * 0.50 + qualPillar.score * 0.30 + riskPillar.score * 0.20
  )
  const overall = getOverallVerdict(overallScore)

  return {
    overallVerdict: overall.verdict,
    overallScore,
    overallLabel: overall.label,
    overallSummary: `${stockName} scores ${overallScore}/100 — ${overall.label}`,
    pillars: [quantPillar, qualPillar, riskPillar],
    newsEvents,
    ticker,
    stockName,
    sector,
    lastUpdated: '2025-01-15',
    stockId,
    profileId,
    peerRank: 1,
    peerTotal: 5,
    topSignals: [],
    topConcerns: [],
    verdictRationale: `Based on comprehensive Quant (${quantPillar.score}/100) + Qual (${qualPillar.score}/100) + Risk (${riskPillar.score}/100) analysis.`,
    positionSizing: 'See detailed analysis',
    entryGuidance: 'See detailed analysis',
  }
}

